import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { API_URL } from '../config';

const Register = () => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [msg, setMsg] = useState({ type: '', text: '' });
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setMsg({ type: '', text: '' });
    try {
      const res = await fetch(`${API_URL}/api/auth/register`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ username, password }),
      });
      const data = await res.json();
      if (res.ok) {
        setMsg({ type: 'success', text: 'Account created! Redirecting to sign in...' });
        setTimeout(() => navigate('/login'), 1500);
      } else {
        setMsg({ type: 'error', text: data.msg || 'Registration failed.' });
      }
    } catch (err) {
      console.error(err);
      setMsg({ type: 'error', text: 'Server error. Please try again later.' });
    }
  };

  return (
    <div className="form-container">
      <h2>Create your account</h2>
      {msg.text && (
        <div style={{ color: msg.type === 'error' ? '#e30000' : '#0071e3', marginBottom: '15px', fontSize: '14px', fontWeight: 500 }}>
          {msg.text}
        </div>
      )}
      <form onSubmit={handleSubmit}>
        <input type="text" placeholder="Apple ID (Username)" value={username} onChange={(e) => setUsername(e.target.value)} required />
        <input type="password" placeholder="Password" value={password} onChange={(e) => setPassword(e.target.value)} required />
        <button type="submit">Create account</button>
      </form>
      <p>Already have an account? <a href="/login">Sign in here.</a></p>
    </div>
  );
};

export default Register;
